            try {
                cont.resume(block())
            } catch (t: Throwable) {
                if (cont.isActive) cont.cancel(t)
            }
        }
    }

internal class SecureStore private constructor(
    private val prefs: SharedPreferences,
    private val logger: PaymentLogger
) {
    companion object {
        private const val FILE_NAME = "payment_secure_store"

        fun create(context: Context, logger: PaymentLogger): SecureStore {
            val appContext = context.applicationContext
            val prefs = try {
                val masterKey = MasterKey.Builder(appContext)
                    .setKeyScheme(MasterKey.KeyScheme.AES256_GCM)
                    .build()
                EncryptedSharedPreferences.create(
                    appContext,
                    FILE_NAME,
                    masterKey,
                    EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
                    EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
                )
            } catch (t: Throwable) {
                logger.w("SecureStore", "EncryptedSharedPreferences unavailable; falling back to private SharedPreferences", t)
                appContext.getSharedPreferences(FILE_NAME, Context.MODE_PRIVATE)
            }
            return SecureStore(prefs, logger)
        }
    }

    fun putString(key: String, value: String) {
        prefs.edit().putString(key, value).apply()
    }

    fun getString(key: String, default: String? = null): String? = prefs.getString(key, default)

    fun remove(key: String) {
        prefs.edit().remove(key).apply()
    }

    fun clear() {
        prefs.edit().clear().apply()
    }
}

internal class WalletStore(
    private val secureStore: SecureStore,
    private val logger: PaymentLogger
) {
    private fun txKey(currency: String) = "wallet_tx_${currency.uppercase()}"
    private fun balKey(currency: String) = "wallet_bal_${currency.uppercase()}"

    fun appendTransaction(tx: WalletTransaction) {
        val currency = tx.currency.uppercase()
        val existing = getTransactions(currency, 5000).toMutableList()
        existing.add(tx)
        val trimmed = if (existing.size > 5000) existing.takeLast(5000) else existing
        secureStore.putString(txKey(currency), WalletJson.encodeTransactions(trimmed))
        val bal = computeBalance(currency, trimmed)
        secureStore.putString(balKey(currency), bal.availableMinor.toString())
    }

    fun getTransactions(currency: String, limit: Int): List<WalletTransaction> {
        val raw = secureStore.getString(txKey(currency), null) ?: return emptyList()
        return try {
            WalletJson.decodeTransactions(raw).takeLast(limit)
        } catch (t: Throwable) {
            logger.w("WalletStore", "Failed to decode transactions; returning empty", t)
            emptyList()
        }
    }

    fun getBalance(currency: String): WalletBalance {
        val cur = currency.uppercase()
        val rawBal = secureStore.getString(balKey(cur), null)
        val bal = rawBal?.toLongOrNull()
        if (bal != null) return WalletBalance(bal, cur)
        val txs = getTransactions(cur, 5000)
        return computeBalance(cur, txs)
    }

    fun clearAll() {
        secureStore.clear()
    }

    private fun computeBalance(currency: String, txs: List<WalletTransaction>): WalletBalance {
        var sum = 0L
        for (t in txs) {
            sum += when (t.type) {
                WalletTransactionType.CREDIT -> t.amountMinor
                WalletTransactionType.DEBIT -> -t.amountMinor
            }
        }
        return WalletBalance(sum.coerceAtLeast(0L), currency.uppercase())
    }
}

internal object WalletJson {
    private fun esc(s: String): String {
        val sb = StringBuilder(s.length + 16)
        for (c in s) {
            when (c) {
                '\\' -> sb.append("\\\\")
                '"' -> sb.append("\\\"")
                '\n' -> sb.append("\\n")
                '\r' -> sb.append("\\r")
                '\t' -> sb.append("\\t")
                else -> sb.append(c)
            }
        }
        return sb.toString()
    }

    fun encodeTransactions(list: List<WalletTransaction>): String {
        val sb = StringBuilder()
        sb.append('[')
        for (i in list.indices) {
            val t = list[i]
            if (i > 0) sb.append(',')
            sb.append('{')
            sb.append("\"id\":\"").append(esc(t.id)).append("\",")
            sb.append("\"type\":\"").append(t.type.name).append("\",")
            sb.append("\"amountMinor\":").append(t.amountMinor).append(',')
            sb.append("\"currency\":\"").append(esc(t.currency)).append("\",")
            sb.append("\"createdAtEpochMs\":").append(t.createdAtEpochMs)
            if (t.reference != null) {
                sb.append(",\"reference\":\"").append(esc(t.reference)).append("\"")
            }
            if (t.metadata.isNotEmpty()) {
                sb.append(",\"metadata\":{")
                var first = true
                for ((k, v) in t.metadata) {
                    if (!first) sb.append(',')
                    first = false
                    sb.append('"').append(esc(k)).append('"').append(':').append('"').append(esc(v)).append('"')
                }
                sb.append('}')
            }
            sb.append('}')
        }
        sb.append(']')
        return sb.toString()
    }

    fun decodeTransactions(json: String): List<WalletTransaction> {
        val p = JsonParser(json)
        return p.parseTransactions()
    }

    private class JsonParser(private val s: String) {
        private var i = 0

        fun parseTransactions(): List<WalletTransaction> {
            skipWs()
            expect('[')
            skipWs()
            val out = ArrayList<WalletTransaction>()
            if (peek() == ']') {
                i++
                return out
            }
            while (true) {
                skipWs()
                out.add(parseTx())
                skipWs()
                val c = next()
                if (c == ']') break
                if (c != ',') error("Expected , or ]")
            }
            return out
        }

        private fun parseTx(): WalletTransaction {
            skipWs()
            expect('{')
            var id: String? = null
            var type: WalletTransactionType? = null
            var amountMinor: Long? = null
            var currency: String? = null
            var createdAt: Long? = null
            var reference: String? = null
            var metadata: Map<String, String> = emptyMap()

            skipWs()
            if (peek() == '}') {
                i++
                error("Empty object")
            }

            while (true) {
                skipWs()
                val key = parseString()
                skipWs()
                expect(':')
                skipWs()
                when (key) {
                    "id" -> id = parseString()
                    "type" -> type = WalletTransactionType.valueOf(parseString())
                    "amountMinor" -> amountMinor = parseNumber()
                    "currency" -> currency = parseString()
                    "createdAtEpochMs" -> createdAt = parseNumber()
                    "reference" -> reference = parseString()
                    "metadata" -> metadata = parseStringMap()
                    else -> skipValue()
                }
                skipWs()
                val c = next()
                if (c == '}') break
                if (c != ',') error("Expected , or }")
            }

            return WalletTransaction(
                id = id ?: error("Missing id"),
                type = type ?: error("Missing type"),
                amountMinor = amountMinor ?: error("Missing amountMinor"),
                currency = currency ?: error("Missing currency"),
                createdAtEpochMs = createdAt ?: error("Missing createdAtEpochMs"),
                reference = reference,
                metadata = metadata
            )
        }

        private fun parseStringMap(): Map<String, String> {
            skipWs()
            expect('{')
            skipWs()
            if (peek() == '}') {
                i++
                return emptyMap()
            }
            val map = LinkedHashMap<String, String>()
            while (true) {
                skipWs()
                val k = parseString()
                skipWs()
                expect(':')
                skipWs()
                val v = parseString()
                map[k] = v
                skipWs()
                val c = next()
                if (c == '}') break
                if (c != ',') error("Expected , or } in map")
            }
            return map
        }

        private fun skipValue() {
            skipWs()
            when (peek()) {
                '"' -> parseString()
                '{' -> {
                    expect('{')
                    var depth = 1
                    while (depth > 0) {
                        val c = next()
                        if (c == '"') skipStringBody()
                        else if (c == '{') depth++
                        else if (c == '}') depth--
                    }
                }
                '[' -> {
                    expect('[')
                    var depth = 1
                    while (depth > 0) {
                        val c = next()
                        if (c == '"') skipStringBody()
                        else if (c == '[') depth++
                        else if (c == ']') depth--
                    }
                }
                else -> {
                    while (i < s.length && s[i] !in charArrayOf(',', '}', ']', ' ', '\n', '\r', '\t')) i++
                }
            }
        }

        private fun parseString(): String {
            expect('"')
            val sb = StringBuilder()
            while (i < s.length) {
                val c = next()
                when (c) {
                    '"' -> return sb.toString()
                    '\\' -> {
                        val e = next()
                        when (e) {
                            '"', '\\', '/' -> sb.append(e)
                            'b' -> sb.append('\b')
                            'f' -> sb.append('\u000C')
                            'n' -> sb.append('\n')
                            'r' -> sb.append('\r')
                            't' -> sb.append('\t')
                            'u' -> {
                                val hex = s.substring(i, i + 4)
                                sb.append(hex.toInt(16).toChar())
                                i += 4
                            }
                            else -> error("Bad escape")
                        }
                    }
                    else -> sb.append(c)
                }
            }
            error("Unterminated string")
        }

        private fun skipStringBody() {
            while (i < s.length) {
                val c = next()
                if (c == '\\') {
                    next()
                } else if (c == '"') {
                    return
                }
            }
            error("Unterminated string")
        }

        private fun parseNumber(): Long {
            skipWs()
            val start = i
            if (peek() == '-') i++
            while (i < s.length && s[i].isDigit()) i++
            val sub = s.substring(start, i)
            return sub.toLongOrNull() ?: error("Bad number")
        }

        private fun skipWs() {
            while (i < s.length) {
                when (s[i]) {
                    ' ', '\n', '\r', '\t' -> i++
                    else -> return
                }
            }
        }

        private fun expect(c: Char) {
            val n = next()
            if (n != c) error("Expected $c got $n")
        }

        private fun next(): Char {
            if (i >= s.length) error("Unexpected EOF")
            return s[i++]
        }

        private fun peek(): Char {
            if (i >= s.length) error("Unexpected EOF")
            return s[i]
        }

        private fun error(msg: String): Nothing = throw IllegalArgumentException("JSON parse error at $i: $msg")
    }
}

class PaymentAppLifecycle private constructor(
    private val app: Application
) : Application.ActivityLifecycleCallbacks {

    companion object {
        @Volatile private var installed = false

        fun install(app: Application) {
            if (installed) return
            installed = true
            app.registerActivityLifecycleCallbacks(PaymentAppLifecycle(app))
        }
    }

    override fun onActivityCreated(activity: Activity, savedInstanceState: Bundle?) {}
    override fun onActivityStarted(activity: Activity) {}
    override fun onActivityResumed(activity: Activity) {
        try {
            PaymentModule.get().connectBilling()
        } catch (_: Throwable) {}
    }
    override fun onActivityPaused(activity: Activity) {}
    override fun onActivityStopped(activity: Activity) {}
    override fun onActivitySaveInstanceState(activity: Activity, outState: Bundle) {}
    override fun onActivityDestroyed(activity: Activity) {}
}

